custom_css:
@import url('https://fonts.googleapis.com/css2?family=Great+Vibes&family=Playfair+Display:ital,wght@0,400;0,600;1,400&family=Spectral:ital,wght@0,400;0,600;1,400;1,600&display=block');

/* Gothic Rose & Gold Custom CSS */

/* --- CHAT AREA & MESSAGES --- */

body #chat {

  --avatar-base-width: 95px !important;

  --avatar-base-height: 95px !important;

}

.mes {

  width: 100% !important;

  max-width: 100% !important;

  box-sizing: border-box !important;

  flex-direction: column !important;

  align-items: center !important;

  position: relative !important;

  border: none !important;

  border-radius: 16px !important;

  padding-top: 40px !important;

  padding-bottom: 18px !important;

  margin-bottom: 0px !important;

  background: transparent !important;

  box-shadow: none !important;

  transition: background-color 0.2s ease, box-shadow 0.2s ease !important;

}

.mes:hover {

  border: none !important;

  box-shadow: none !important;

}

/* --- AVATAR & NAME --- */

.mesAvatarWrapper {

  flex-direction: column !important;

  justify-content: center !important;

  align-items: center !important;

  margin-bottom: 15px !important;

  margin-right: 0 !important;

  margin-left: 0 !important;

  padding-bottom: 0 !important;

}

.mes_block {

  width: 100% !important;

  margin-left: 0 !important;

  margin-right: 0 !important;

}

#chat .mes .avatar {

  position: relative !important;

  overflow: visible !important;

  width: var(--avatar-base-width) !important;

  height: var(--avatar-base-width) !important;

  aspect-ratio: 1 / 1 !important;

  border-radius: 50% !important;

  border: none !important;

  box-shadow: 0 0 20px 5px rgba(100, 15, 25, 0.7) !important;

  margin: 0 auto !important;

}

#chat .mes .avatar img {

  width: 100% !important;

  height: 100% !important;

  aspect-ratio: 1 / 1 !important;

  border-radius: 50% !important;

  object-fit: cover !important;

}

body.big-avatars #chat .mes .avatar {

  width: calc(var(--avatar-base-width) * var(--big-avatar-width-factor, 1.2)) !important;

  height: calc(var(--avatar-base-width) * var(--big-avatar-width-factor, 1.2)) !important;

}

body.big-avatars #chat .mes .avatar img {

  width: 100% !important;

  height: 100% !important;

}

#chat .mes .avatar::after {

  content: "" !important;

  position: absolute !important;

  top: 50% !important;

  left: 50% !important;

  transform: translate(-50%, -50%) !important;

  width: 130% !important;

  height: 130% !important;

  background-image: url('https://i.postimg.cc/CL0R2Zyh/sozdaj-arkij-zelenyj-fon-hromakej-202606171636-kopia.png') !important;

  background-size: contain !important;

  background-repeat: no-repeat !important;

  background-position: center !important;

  pointer-events: none !important;

  z-index: 10 !important;



}

/* --- TEXT & TYPOGRAPHY --- */

body, .mes_text {

  font-family: 'Spectral', serif !important;

  line-height: 1.6 !important;

  letter-spacing: 0.05em !important;

  -webkit-font-smoothing: antialiased !important;

  -moz-osx-font-smoothing: grayscale !important;

  text-rendering: optimizeLegibility !important;

}

#chat .mes .mes_text {

  padding-left: 15px !important;

  padding-right: 15px !important;

  box-sizing: border-box !important;

}

.mes_text b, .mes_text strong {

  color: #DEBA6F !important;

  font-weight: 600 !important;

}

.mes_text i, .mes_text em {

  color: #C4BCAE !important;

}

.mes_text u {

  text-decoration-color: #8B0000 !important;

  text-decoration-thickness: 2px !important;

  text-underline-offset: 3px !important;

}

.mes_text del {

  color: #C4BCAE !important;

  text-decoration-color: #660000 !important;

}

pre, code, .markdown-body pre, .markdown-body code {

  font-family: Consolas, "Courier New", monospace !important;

  letter-spacing: normal !important;

}

h1, h2, h3, h4, h5, h6, .standoutHeader, .ch_name {

  font-family: 'Playfair Display', serif !important;

  letter-spacing: 0.06em !important;

  font-weight: 600 !important;

  color: #E2C275 !important;

  text-shadow: 0 0 6px rgba(110, 21, 26, 0.8) !important;

}

.mes_block .ch_name > .flex1 {

  display: flex !important;

  justify-content: center !important;

  align-items: center !important;

  width: 100% !important;

}

.mes_block .ch_name .alignItemsBaseline {

  display: flex !important;

  flex-direction: column !important;

  align-items: center !important;

  justify-content: center !important;

  width: 100% !important;

  gap: 2px !important;

}

.mes_block .ch_name .name_text {

  color: #E2C275 !important;

  text-shadow: 0 0 6px rgba(110, 21, 26, 0.8) !important;

  font-family: 'Great Vibes', cursive !important;

  font-size: 2.2em !important;

  font-weight: normal !important;

  display: inline-block !important;

}

.mes_block .ch_name .timestamp {

  margin-left: 0 !important;

  font-size: 0.8em !important;

  font-family: 'Spectral', serif !important;

  opacity: 0.7 !important;

}

.mes:hover .mes_buttons,

.mes:active .mes_buttons,

.mes:focus-within .mes_buttons {

  opacity: 1 !important;

  pointer-events: auto !important;

}

/* --- UI ELEMENTS & SCROLLBAR --- */

::-webkit-scrollbar {

  width: 10px !important;

  background: rgba(15, 5, 8, 0.95) !important;

}

::-webkit-scrollbar-thumb {

  background: #220810 !important;

  border: 2px solid rgba(15, 5, 8, 0.95) !important;

  border-radius: 5px !important;

}

::-webkit-scrollbar-thumb:hover {

  background: #330C18 !important;

}

select, .form-control, .ui-widget-content {

  background-color: rgba(30, 10, 14, 0.9) !important;

  color: #F0E6CB !important;

  border: 1px solid rgba(110, 21, 26, 0.3) !important;

  border-radius: 6px !important;

}

input[type="text"], input[type="search"], input[type="number"], textarea, .form-control {

  background-color: rgba(22, 6, 10, 0.9) !important;

  color: #F0E6CB !important;

  border: 1px solid rgba(110, 21, 26, 0.3) !important;

  box-shadow: inset 0 2px 4px rgba(0, 0, 0, 0.6) !important;

}

input[type="text"]:focus, textarea:focus, .form-control:focus {

  border-color: rgba(163, 123, 126, 0.4) !important;

  box-shadow: 0 0 10px rgba(110, 21, 26, 0.5), inset 0 2px 4px rgba(0, 0, 0, 0.6) !important;

}

#send_form {

  border: 1px solid rgba(110, 21, 26, 0.3) !important;

  background-color: rgba(20, 6, 10, 0.9) !important;

  border-radius: 12px !important;

  box-shadow: 0 4px 15px rgba(0, 0, 0, 0.5) !important;

}

#send_form:focus-within {

  border-color: rgba(163, 123, 126, 0.4) !important;

}

#top-bar {

  background-color: rgba(20, 6, 10, 0.95) !important;

  border-bottom: 1px solid rgba(110, 21, 26, 0.3) !important;

  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.5) !important;

}

#send_textarea {

  border: none !important;

  box-shadow: none !important;

  color: #F0E6CB !important;

}

#send_textarea::placeholder {

  color: rgba(240, 230, 203, 0.5) !important;

}

small, .hint, .text-muted {

  color: rgba(240, 230, 203, 0.65) !important;

  font-style: normal !important;

}

#bg_menu, 

.menu_overlay, 

.drawer-content, 

#shadow_popup, 

.m-dialog:not(.transparent_dialogue_popup), 

.popup:not(.transparent_dialogue_popup), 

.popup-content:not(.transparent_dialogue_popup .popup-content) {

  background-color: #14060a !important;

}

input[type=range] {

  accent-color: #3D1A39 !important;

}

hr {
  border: 0 !important;
  height: 1px !important;
  background-image: linear-gradient(to right, transparent, rgba(222, 186, 111, 0.6), transparent) !important;
  margin: 15px 0 !important;
}

input[type=range]::-webkit-slider-runnable-track {

  background-color: transparent !important; box-shadow: none !important;

}

input[type=range]::-moz-range-track {

  background-color: transparent !important; box-shadow: none !important;

}

#preloader {

    background-color: #0A0204 !important;

    background-image: none !important;

    backdrop-filter: none !important;

    -webkit-backdrop-filter: none !important;

}

.mes_timer, .tokenCounterDisplay, .mesIDDisplay {

    display: none !important;

}

.mes_block .ch_name .mes_buttons {
  position: absolute !important;
  top: 5px !important;
  right: 5px !important;
  left: 5px !important;
  transform: none !important;
  opacity: 0 !important;
  pointer-events: none !important;
  transition: opacity 0.2s ease-in-out !important;
  z-index: 9999 !important;
  display: flex !important;
  flex-wrap: nowrap !important;
  justify-content: flex-end !important;
  overflow-x: auto !important;
  overflow-y: hidden !important;
  scrollbar-width: none !important; /* Firefox */
  -ms-overflow-style: none !important; /* IE and Edge */
}
.mes_block .ch_name .mes_buttons::-webkit-scrollbar {
  display: none !important; /* Chrome, Safari, Opera */
}

.mes:hover .mes_block .ch_name .mes_buttons,
.mes:active .mes_block .ch_name .mes_buttons,
.mes:focus-within .mes_block .ch_name .mes_buttons {
  opacity: 1 !important;
  pointer-events: auto !important;
}

input[type=range], input[type=range]:focus, input[type=range]:hover {
  box-shadow: none !important;
  outline: none !important;
  filter: none !important;
}

.menu_overlay, #shadow_popup, .drawer-overlay, .m-dialog-overlay, dialog::backdrop {
  backdrop-filter: none !important;
  -webkit-backdrop-filter: none !important;
  background-color: rgba(10, 2, 4, 0.8) !important; 
}

.drawer-content, #right-nav, #left-nav, #bg_menu, #shadow_popup, .popup-content {
  overflow-x: hidden !important;
}

#chat .mes:has(.del_checkbox:checked) {
  background-color: rgba(163, 123, 126, 0.08) !important;
  box-shadow: inset 0 0 10px rgba(163, 123, 126, 0.15) !important;
  border: 1px solid rgba(163, 123, 126, 0.2) !important;
}

#chat .mes .del_checkbox {
  position: absolute !important;
  top: 20px !important;
  left: 10px !important;
  transform: scale(1.5) !important;
  z-index: 9999 !important;
  outline: 2px solid #14060a !important; 
  cursor: pointer !important;
}

.mes_block .ch_name .mes_buttons {
  flex-wrap: nowrap !important;
  white-space: nowrap !important;
}

:root {
  --SmartThemeBlurStrength: 0px !important;
}
#popup-overlay, .m-dialog-overlay, dialog::backdrop {
  backdrop-filter: none !important;
  -webkit-backdrop-filter: none !important;
  background-color: rgba(10, 2, 4, 0.9) !important;
}

.past_chat_item .avatar, .past_chat_item .avatar img {
  width: 38px !important;
  height: 38px !important;
  min-width: 38px !important;
  min-height: 38px !important;
  border-radius: 50% !important;
}

#toast-container {
  top: 15px !important;
  left: 0 !important;
  right: 0 !important;
  margin: 0 auto !important;
  width: fit-content !important;
  pointer-events: none !important;
}
#toast-container > div {
  pointer-events: auto !important;
  margin: 0 auto 6px auto !important;
  box-shadow: 0 4px 15px rgba(0,0,0,0.5) !important;
  opacity: 0.95 !important;
}
.toast-title, .toast-message, .toast-message * {
  text-shadow: none !important;
  font-family: "Spectral", serif !important;
  font-weight: normal !important;
  letter-spacing: 0.05em !important;
}

#left-nav .avatar,
#left-nav .avatar img,
.past_chat_item .avatar,
.past_chat_item .avatar img,
#rm_recent_chats_list .mes .avatar,
#rm_recent_chats_list .mes .avatar img {
  width: 38px !important;
  height: 38px !important;
  min-width: 38px !important;
  min-height: 38px !important;
  border-radius: 50% !important;
}
#left-nav .avatar::after,
.past_chat_item .avatar::after,
#rm_recent_chats_list .mes .avatar::after {
  display: none !important;
  background-image: none !important;
}

#chat_input_buttons,
#send_form #options_button,
#send_form .justifyCenter {
  display: flex !important;
  flex-wrap: nowrap !important;
  flex-direction: row !important;
}
#chat_input_buttons > *,
#send_form .menu_button {
  flex-shrink: 0 !important;
}

#send_form.compact #leftSendForm, 
#send_form.compact #rightSendForm, 
#leftSendForm, 
#rightSendForm {
  flex-direction: row !important;
  flex-wrap: nowrap !important;
}

.recentChat .avatar,
.recentChat .avatar img {
  width: 50px !important;
  height: 50px !important;
  min-width: 50px !important;
  min-height: 50px !important;
  max-width: 50px !important;
  max-height: 50px !important;
}
.recentChat .avatar::after {
  display: none !important;
  background-image: none !important;
}

#leftSendForm, 
#rightSendForm, 
#send_form.compact #leftSendForm, 
#send_form.compact #rightSendForm {
  flex-direction: row !important;
  flex-wrap: nowrap !important;
  width: max-content !important;
}
#leftSendForm > *, 
#rightSendForm > * {
  flex-shrink: 0 !important;
  margin: 0 2px !important;
}

.mes::after {

  content: "";

  display: block;

  width: 100%;

  height: 20px;

  background-image: url("https://i.postimg.cc/XqqkvncV/razdelitel%27.png");

  background-size: contain;

  background-position: center;

  background-repeat: no-repeat;

  margin-top: 10px;
  transform: translateX(5px) !important;

  opacity: 0.9;

}


blockquote, .markdown-body blockquote {
  background-color: rgba(222, 186, 111, 0.08) !important;
  border-left: 3px solid #DEBA6F !important;
  padding: 10px 15px !important;
  margin: 15px 0 !important;
  border-radius: 0 8px 8px 0 !important;
}

.mes_text b i, .mes_text strong em,
.mes_text i b, .mes_text em strong {
  color: #DEBA6F !important;
}
